import{_ as a,o as i,c as t,ag as r}from"./chunks/framework.CvgP6Fyv.js";const u=JSON.parse('{"title":"What is SendGrail?","description":"","frontmatter":{},"headers":[],"relativePath":"guide/what-is-sendgrail.md","filePath":"guide/what-is-sendgrail.md"}'),o={name:"guide/what-is-sendgrail.md"};function n(s,e,l,d,h,c){return i(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="what-is-sendgrail" tabindex="-1">What is SendGrail? <a class="header-anchor" href="#what-is-sendgrail" aria-label="Permalink to &quot;What is SendGrail?&quot;">​</a></h1><p>SendGrail is a WordPress plugin that fixes email delivery by routing all outgoing mail through authenticated SMTP providers instead of the unreliable default PHP <code>mail()</code> function.</p><h2 id="the-problem-with-wordpress-email" tabindex="-1">The Problem with WordPress Email <a class="header-anchor" href="#the-problem-with-wordpress-email" aria-label="Permalink to &quot;The Problem with WordPress Email&quot;">​</a></h2><p>Out of the box, WordPress sends email using PHP&#39;s built-in <code>mail()</code> function. This approach has serious problems:</p><ul><li><strong>Emails land in spam.</strong> Messages sent via <code>mail()</code> lack proper authentication (SPF, DKIM, DMARC), so mail servers treat them as suspicious.</li><li><strong>Emails silently fail.</strong> Shared hosting environments often restrict or disable <code>mail()</code> entirely. WordPress gives no indication when this happens.</li><li><strong>No delivery visibility.</strong> There is no logging, no tracking, and no way to know if an email was actually delivered.</li><li><strong>No retry or fallback.</strong> If sending fails, the email is lost with no recovery mechanism.</li></ul><p>This means password resets, WooCommerce order confirmations, contact form submissions, and other critical emails may never reach their recipients.</p><h2 id="how-sendgrail-fixes-it" tabindex="-1">How SendGrail Fixes It <a class="header-anchor" href="#how-sendgrail-fixes-it" aria-label="Permalink to &quot;How SendGrail Fixes It&quot;">​</a></h2><p>SendGrail hooks into WordPress&#39;s <code>wp_mail()</code> function and routes all outgoing email through a properly configured SMTP connection. This ensures emails are authenticated, encrypted, and delivered reliably.</p><h2 id="key-benefits" tabindex="-1">Key Benefits <a class="header-anchor" href="#key-benefits" aria-label="Permalink to &quot;Key Benefits&quot;">​</a></h2><h3 id="_13-smtp-providers" tabindex="-1">13+ SMTP Providers <a class="header-anchor" href="#_13-smtp-providers" aria-label="Permalink to &quot;13+ SMTP Providers&quot;">​</a></h3><p>Connect to Gmail, Outlook, SendGrid, Mailgun, Amazon SES, Postmark, Mandrill, Elastic Email, SMTP2GO, Mailtrap, Zoho Mail, Brevo, or any custom SMTP server. Each provider has a pre-configured template so you only need to enter your credentials.</p><h3 id="email-logging" tabindex="-1">Email Logging <a class="header-anchor" href="#email-logging" aria-label="Permalink to &quot;Email Logging&quot;">​</a></h3><p>Every email your site sends is logged with full details: recipients, subject, headers, status, and optionally the full message body. Search, filter, and review your email history at any time.</p><h3 id="open-and-click-tracking" tabindex="-1">Open and Click Tracking <a class="header-anchor" href="#open-and-click-tracking" aria-label="Permalink to &quot;Open and Click Tracking&quot;">​</a></h3><p>Know when recipients open your emails and which links they click. Tracking data is collected automatically and displayed on the dashboard.</p><h3 id="smart-routing" tabindex="-1">Smart Routing <a class="header-anchor" href="#smart-routing" aria-label="Permalink to &quot;Smart Routing&quot;">​</a></h3><p>Route emails through different SMTP connections based on the sender address, recipient address, or domain. For example, send transactional emails through SendGrid and marketing emails through Mailgun.</p><h3 id="one-click-migration" tabindex="-1">One-Click Migration <a class="header-anchor" href="#one-click-migration" aria-label="Permalink to &quot;One-Click Migration&quot;">​</a></h3><p>Switching from another SMTP plugin? SendGrail auto-detects settings from WP Mail SMTP, Post SMTP, FluentSMTP, and Easy WP SMTP, then imports them in one click. Your original settings are preserved.</p><h3 id="weekly-reports" tabindex="-1">Weekly Reports <a class="header-anchor" href="#weekly-reports" aria-label="Permalink to &quot;Weekly Reports&quot;">​</a></h3><p>Receive a scheduled email summary with delivery statistics, failure counts, and engagement metrics. Configure which day and email address receives the report.</p><h3 id="fallback-reliability" tabindex="-1">Fallback Reliability <a class="header-anchor" href="#fallback-reliability" aria-label="Permalink to &quot;Fallback Reliability&quot;">​</a></h3><p>Configure a backup SMTP connection. If your primary provider fails, SendGrail automatically tries the fallback connection before resorting to WordPress default mail.</p><h2 id="requirements" tabindex="-1">Requirements <a class="header-anchor" href="#requirements" aria-label="Permalink to &quot;Requirements&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Requirement</th><th>Minimum Version</th></tr></thead><tbody><tr><td>PHP</td><td>8.0+</td></tr><tr><td>WordPress</td><td>6.0+</td></tr><tr><td>PHP Extensions</td><td>OpenSSL, cURL</td></tr></tbody></table><p>SendGrail works with any hosting environment that supports outbound SMTP connections on standard ports (25, 465, 587, 2525).</p>',26)])])}const p=a(o,[["render",n]]);export{u as __pageData,p as default};
